/* Minimal local JSZip-compatible reader for .apkg imports. Supports stored and deflate ZIP entries. */
(function(global){
  function u16(d,o){return d[o]|(d[o+1]<<8)} function u32(d,o){return (d[o]|(d[o+1]<<8)|(d[o+2]<<16)|(d[o+3]<<24))>>>0}
  async function inflateRaw(bytes){
    if (typeof DecompressionStream === 'undefined') throw new Error('Dieser Browser unterstützt keine lokale ZIP-Deflate-Dekompression.');
    try { return await inflateWithFormat(bytes, 'deflate-raw'); } catch (_) { return inflateWithFormat(bytes, 'deflate'); }
  }
  async function inflateWithFormat(bytes, format){
    const stream = new Blob([bytes]).stream().pipeThrough(new DecompressionStream(format));
    return new Uint8Array(await new Response(stream).arrayBuffer());
  }
  class MiniZipEntry{
    constructor(bytes, entry){ this._bytes=bytes; this._entry=entry; }
    async async(type){
      const e=this._entry; const nameLen=u16(this._bytes,e.localOffset+26); const extraLen=u16(this._bytes,e.localOffset+28);
      const start=e.localOffset+30+nameLen+extraLen; let data=this._bytes.slice(start,start+e.compressedSize);
      if(e.method===8) data=await inflateRaw(data); else if(e.method!==0) throw new Error('ZIP-Kompressionsmethode nicht unterstützt: '+e.method);
      if(type==='uint8array') return data; if(type==='arraybuffer') return data.buffer.slice(data.byteOffset,data.byteOffset+data.byteLength);
      return new TextDecoder().decode(data);
    }
  }
  class MiniZip{
    constructor(bytes, entries){ this._bytes=bytes; this._entries=entries; }
    file(name){ const e=this._entries.get(name); return e ? new MiniZipEntry(this._bytes,e) : null; }
    static async loadAsync(file){
      const bytes=new Uint8Array(await file.arrayBuffer()); let eocd=-1;
      for(let i=bytes.length-22;i>=0 && i>bytes.length-66000;i--){ if(u32(bytes,i)===0x06054b50){ eocd=i; break; } }
      if(eocd<0) throw new Error('ZIP-Ende wurde nicht gefunden.');
      const total=u16(bytes,eocd+10); let offset=u32(bytes,eocd+16); const entries=new Map();
      for(let i=0;i<total;i++){
        if(u32(bytes,offset)!==0x02014b50) throw new Error('ZIP-Zentralverzeichnis ist beschädigt.');
        const method=u16(bytes,offset+10); const compressedSize=u32(bytes,offset+20); const fileNameLength=u16(bytes,offset+28);
        const extraLength=u16(bytes,offset+30); const commentLength=u16(bytes,offset+32); const localOffset=u32(bytes,offset+42);
        const name=new TextDecoder().decode(bytes.slice(offset+46,offset+46+fileNameLength));
        entries.set(name,{method,compressedSize,localOffset}); offset += 46+fileNameLength+extraLength+commentLength;
      }
      return new MiniZip(bytes, entries);
    }
  }
  global.JSZip=MiniZip;
})(globalThis);
